    uniffiRustCall() { _status ->
    UniffiLib.uniffi_tracelet_core_fn_func_haversine(
    
        FfiConverterDouble.lower(`lat1`),FfiConverterDouble.lower(`lon1`),FfiConverterDouble.lower(`lat2`),FfiConverterDouble.lower(`lon2`),_status)
}
    )
